import{_ as s,o as a,c as e,aw as n}from"./chunks/framework.Dq2onT5h.js";const o=JSON.parse('{"title":"Base Fee Redirect","description":"","frontmatter":{"head":[["meta",{"name":"og:title","content":"Base Fee Redirect | Evolve"},{"name":"og:description","content":false}]]},"headers":[],"relativePath":"ev-reth/features/base-fee-redirect.md","filePath":"ev-reth/features/base-fee-redirect.md","lastUpdated":1772446570000}');const l=s({name:"ev-reth/features/base-fee-redirect.md"},[["render",function(s,o,l,t,p,r){return a(),e("div",null,[...o[0]||(o[0]=[n('<h1 id="base-fee-redirect" tabindex="-1">Base Fee Redirect <a class="header-anchor" href="#base-fee-redirect" aria-label="Permalink to &quot;Base Fee Redirect&quot;">​</a></h1><p>Redirect EIP-1559 base fees to a treasury address instead of burning them.</p><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>In standard Ethereum, base fees are burned. ev-reth allows redirecting these fees to a specified address, enabling:</p><ul><li>Protocol revenue collection</li><li>Treasury funding</li><li>DAO-controlled fee distribution</li></ul><h2 id="configuration" tabindex="-1">Configuration <a class="header-anchor" href="#configuration" aria-label="Permalink to &quot;Configuration&quot;">​</a></h2><p>In your chainspec (<code>genesis.json</code>):</p><div class="language-json"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki ev-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#767676;">{</span></span>\n<span class="line"><span style="color:#94EEFF77;">  &quot;</span><span style="color:#94EEFF;">config</span><span style="color:#94EEFF77;">&quot;</span><span style="color:#767676;">:</span><span style="color:#767676;"> {</span></span>\n<span class="line"><span style="color:#94EEFF77;">    &quot;</span><span style="color:#94EEFF;">evolve</span><span style="color:#94EEFF77;">&quot;</span><span style="color:#767676;">:</span><span style="color:#767676;"> {</span></span>\n<span class="line"><span style="color:#94EEFF77;">      &quot;</span><span style="color:#94EEFF;">baseFeeSink</span><span style="color:#94EEFF77;">&quot;</span><span style="color:#767676;">:</span><span style="color:#BFF3C280;"> &quot;</span><span style="color:#BFF3C2;">0xYOUR_TREASURY_ADDRESS</span><span style="color:#BFF3C280;">&quot;</span><span style="color:#767676;">,</span></span>\n<span class="line"><span style="color:#94EEFF77;">      &quot;</span><span style="color:#94EEFF;">baseFeeRedirectActivationHeight</span><span style="color:#94EEFF77;">&quot;</span><span style="color:#767676;">:</span><span style="color:#FFECB6;"> 0</span></span>\n<span class="line"><span style="color:#767676;">    }</span></span>\n<span class="line"><span style="color:#767676;">  }</span></span>\n<span class="line"><span style="color:#767676;">}</span></span></code></pre></div><table tabindex="0"><thead><tr><th>Field</th><th>Description</th></tr></thead><tbody><tr><td><code>baseFeeSink</code></td><td>Address to receive base fees</td></tr><tr><td><code>baseFeeRedirectActivationHeight</code></td><td>Block height to activate (0 = genesis)</td></tr></tbody></table><h2 id="how-it-works" tabindex="-1">How It Works <a class="header-anchor" href="#how-it-works" aria-label="Permalink to &quot;How It Works&quot;">​</a></h2><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki ev-dark vp-code" tabindex="0"><code><span class="line"><span>Transaction Fee = Base Fee + Priority Fee</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>Standard Ethereum:</span></span>\n<span class="line"><span>├── Base Fee    → Burned</span></span>\n<span class="line"><span>└── Priority Fee → Block producer</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>With Base Fee Redirect:</span></span>\n<span class="line"><span>├── Base Fee    → baseFeeSink address</span></span>\n<span class="line"><span>└── Priority Fee → Block producer (fee recipient)</span></span></code></pre></div><h2 id="example" tabindex="-1">Example <a class="header-anchor" href="#example" aria-label="Permalink to &quot;Example&quot;">​</a></h2><p>Treasury at <code>0x1234...</code>:</p><div class="language-json"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki ev-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#767676;">{</span></span>\n<span class="line"><span style="color:#94EEFF77;">  &quot;</span><span style="color:#94EEFF;">config</span><span style="color:#94EEFF77;">&quot;</span><span style="color:#767676;">:</span><span style="color:#767676;"> {</span></span>\n<span class="line"><span style="color:#94EEFF77;">    &quot;</span><span style="color:#94EEFF;">chainId</span><span style="color:#94EEFF77;">&quot;</span><span style="color:#767676;">:</span><span style="color:#FFECB6;"> 1337</span><span style="color:#767676;">,</span></span>\n<span class="line"><span style="color:#94EEFF77;">    &quot;</span><span style="color:#94EEFF;">evolve</span><span style="color:#94EEFF77;">&quot;</span><span style="color:#767676;">:</span><span style="color:#767676;"> {</span></span>\n<span class="line"><span style="color:#94EEFF77;">      &quot;</span><span style="color:#94EEFF;">baseFeeSink</span><span style="color:#94EEFF77;">&quot;</span><span style="color:#767676;">:</span><span style="color:#BFF3C280;"> &quot;</span><span style="color:#BFF3C2;">0x1234567890123456789012345678901234567890</span><span style="color:#BFF3C280;">&quot;</span><span style="color:#767676;">,</span></span>\n<span class="line"><span style="color:#94EEFF77;">      &quot;</span><span style="color:#94EEFF;">baseFeeRedirectActivationHeight</span><span style="color:#94EEFF77;">&quot;</span><span style="color:#767676;">:</span><span style="color:#FFECB6;"> 0</span></span>\n<span class="line"><span style="color:#767676;">    }</span></span>\n<span class="line"><span style="color:#767676;">  }</span></span>\n<span class="line"><span style="color:#767676;">}</span></span></code></pre></div><p>All base fees from block 0 onward go to the treasury.</p><h2 id="activation-at-later-height" tabindex="-1">Activation at Later Height <a class="header-anchor" href="#activation-at-later-height" aria-label="Permalink to &quot;Activation at Later Height&quot;">​</a></h2><p>To activate after chain launch:</p><div class="language-json"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki ev-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#767676;">{</span></span>\n<span class="line"><span style="color:#94EEFF77;">  &quot;</span><span style="color:#94EEFF;">config</span><span style="color:#94EEFF77;">&quot;</span><span style="color:#767676;">:</span><span style="color:#767676;"> {</span></span>\n<span class="line"><span style="color:#94EEFF77;">    &quot;</span><span style="color:#94EEFF;">evolve</span><span style="color:#94EEFF77;">&quot;</span><span style="color:#767676;">:</span><span style="color:#767676;"> {</span></span>\n<span class="line"><span style="color:#94EEFF77;">      &quot;</span><span style="color:#94EEFF;">baseFeeSink</span><span style="color:#94EEFF77;">&quot;</span><span style="color:#767676;">:</span><span style="color:#BFF3C280;"> &quot;</span><span style="color:#BFF3C2;">0x...</span><span style="color:#BFF3C280;">&quot;</span><span style="color:#767676;">,</span></span>\n<span class="line"><span style="color:#94EEFF77;">      &quot;</span><span style="color:#94EEFF;">baseFeeRedirectActivationHeight</span><span style="color:#94EEFF77;">&quot;</span><span style="color:#767676;">:</span><span style="color:#FFECB6;"> 1000000</span></span>\n<span class="line"><span style="color:#767676;">    }</span></span>\n<span class="line"><span style="color:#767676;">  }</span></span>\n<span class="line"><span style="color:#767676;">}</span></span></code></pre></div><p>Fees are burned until block 1,000,000, then redirected.</p><h2 id="use-cases" tabindex="-1">Use Cases <a class="header-anchor" href="#use-cases" aria-label="Permalink to &quot;Use Cases&quot;">​</a></h2><ul><li><strong>Protocol treasury</strong> — Fund development, grants, or operations</li><li><strong>Staking rewards</strong> — Distribute to token holders</li><li><strong>Burn address</strong> — Set to <code>0x0</code> to explicitly burn (default behavior)</li></ul>',21)])])}]]);export{o as __pageData,l as default};
